      { cat: "Kap 1", q: "Was ist Information nach Shannon?", a: "Beseitigung von Ungewissheit – statistischer Aspekt, nicht Semantik. Je unwahrscheinlicher ein Ereignis, desto größer der Informationsgehalt.", keyTerms: ["desto größer der Informationsgehalt", "Beseitigung von Ungewissheit", "statistischer Aspekt", "Je unwahrscheinlicher ein Ereignis", "nicht Semantik"] },
      { cat: "Kap 1", q: "Was ist 1 bit?", a: "Der Informationsgehalt, der aus der Auswahl aus zwei gleich wahrscheinlichen Möglichkeiten resultiert (Ja-Nein-Entscheidung). Maßeinheit: bit/Zeichen oder Shannon (Sh).", keyTerms: ["bit/Zeichen oder Shannon", "Der Informationsgehalt", "der aus der Auswahl aus", "Maßeinheit"] },
      { cat: "Kap 1", q: "Wie berechnet man den Entscheidungsgehalt H0?", a: "H0 = log2(m) = ld(m), wobei m die Anzahl gleich wahrscheinlicher Zustände ist. Beispiel: Würfel (m=6) → H0 = 2,58 bit.", keyTerms: ["wobei m die Anzahl gleich", "Würfel", "58 bit", "H0 = log2 = ld", "Beispiel"] },
      { cat: "Kap 1", q: "Was ist die Entropie H?", a: "Der mittlere Informationsgehalt: H = -Σ P(xi) · log2(P(xi)). Maximum bei gleichen Wahrscheinlichkeiten (= H0). Ein sicheres Ereignis hat H = 0.", keyTerms: ["Maximum bei gleichen Wahrscheinlichkeiten", "Der mittlere Informationsgehalt", "H = -Σ P · log2)", "Ein sicheres Ereignis hat H"] },
      { cat: "Kap 1", q: "Was ist Redundanz?", a: "RQ = H0 - H. Der Anteil einer Nachricht, der keine Information übermittelt. Relative Redundanz: r = (H0 - H)/H0. Deutsche Sprache: ca. 66% redundant.", keyTerms: ["r = (H0", "66% redundant", "Der Anteil einer Nachricht", "der keine Information übermittelt", "Relative Redundanz"] },
      { cat: "Kap 1", q: "Wie hängen Information, Daten, Nachricht und Signal zusammen?", a: "Information → als Daten dargestellt → als Nachricht übertragen → mittels Signalen physisch transportiert. Zeichen bilden Alphabet, Wörter aus k Zeichen und n Stellen: m = k^n.", keyTerms: ["mittels Signalen physisch transportiert", "Zeichen bilden Alphabet", "als Daten dargestellt", "als Nachricht übertragen", "Information"] },
      { cat: "Kap 2", q: "Was sind die Komponenten des Shannon-Modells?", a: "Quelle → Sender → Kanal (+ Störungen) → Empfänger → Ziel. Der Sender passt die Nachricht an den Kanal an, der Empfänger führt die inverse Operation durch.", keyTerms: ["Kanal", "der Empfänger führt die inverse", "Quelle", "Sender", "Ziel"] },
      { cat: "Kap 2", q: "Was ist eine Markow-Quelle?", a: "Eine Quelle mit Gedächtnis – die Wahrscheinlichkeit eines Zeichens hängt vom vorherigen ab. Beispiel: Deutsche Sprache (q → u, sch). Bedingte Entropie ≤ unbedingte Entropie.", keyTerms: ["Deutsche Sprache (q", "Eine Quelle mit Gedächtnis", "die Wahrscheinlichkeit eines Zeichens hängt", "sch)", "Bedingte Entropie ≤ unbedingte Entropie"] },
      { cat: "Kap 2", q: "Was ist Transinformation?", a: "T(X;Y) = H(X) - H(X|Y) = die tatsächlich übertragene Nutzinformation. H(X|Y) ist die Äquivokation (Restungewissheit), H(Y|X) die Irrelevanz (Störinformation).", keyTerms: ["T(X", "H = die tatsächlich übertragene Nutzinformation", "H ist die Äquivokation", "H die Irrelevanz"] },
      { cat: "Kap 2", q: "Was ist die Kanalkapazität C (theoretisch)?", a: "C = max T(X;Y) – der größtmögliche Informationsfluss über einen gestörten Kanal. Für symmetrisch gestörten Binärkanal: C = 1 + p·ld(p) + (1-p)·ld(1-p).", keyTerms: ["C = max T(X", "Für symmetrisch gestörten Binärkanal", "der größtmögliche Informationsfluss über einen", "C = 1 + p·ld"] },
      { cat: "Kap 2", q: "Was ist der Informationsfluss?", a: "F = vs · T(X;Y) [bit/s]. vs ist die Symbolrate. Maximum bei C · vs. Transinformation × Zeichenrate ergibt den Fluss in bit/s.", keyTerms: ["Transinformation × Zeichenrate ergibt den", "Y) [bit/s]", "vs ist die Symbolrate", "F = vs · T(X", "Maximum bei C · vs"] },
      { cat: "Kap 3", q: "Wie werden Signale klassifiziert?", a: "Nach Wert: wertkontinuierlich (analog) vs. wertdiskret (digital). Nach Zeit: zeitkontinuierlich vs. zeitdiskret. Analoges Signal: wertkont. + zeitkont. Digitales Signal: wertdiskret + zeitdiskret.", keyTerms: ["wertkontinuierlich  vs", "wertdiskret", "Analoges Signal", "Digitales Signal", "Nach Wert"] },
      { cat: "Kap 3", q: "Was besagt das Abtasttheorem?", a: "fA ≥ 2·fG (Nyquist-Shannon). Die Abtastfrequenz muss mindestens doppelt so groß wie die Grenzfrequenz sein, um das Signal verlustfrei rekonstruieren zu können.", keyTerms: ["fA ≥ 2·fG", "Die Abtastfrequenz muss mindestens doppelt", "um das Signal verlustfrei rekonstruieren", "Nyquist", "Shannon"] },
      { cat: "Kap 3", q: "Was ist der Nachrichtenquader?", a: "Grafische Darstellung der drei Signaleigenschaften: Bandbreite × Dynamik × Dauer = konstant. Die Größen sind gegeneinander austauschbar. Muss durch das Kanalfenster passen.", keyTerms: ["Bandbreite × Dynamik × Dauer", "Grafische Darstellung der drei Signaleigenschaften", "Die Größen sind gegeneinander austauschbar", "Muss durch das Kanalfenster passen"] },
      { cat: "Kap 3", q: "Was sagt die Fourier-Reihe aus?", a: "Jedes periodische Signal ist eine Überlagerung von Sinus-/Cosinusschwingungen. Rechtecksignal enthält nur ungerade Oberschwingungen (1f, 3f, 5f...). Mehr Oberschwingungen = bessere Annäherung.", keyTerms: ["Rechtecksignal enthält nur ungerade Oberschwingungen (1f", "Jedes periodische Signal ist eine", "Mehr Oberschwingungen = bessere Annäherung", "Signal", "Überlagerung"] },
      { cat: "Kap 3", q: "Was ist das Tastverhältnis?", a: "D = τ/T0 (Impulsdauer/Periodendauer). Bestimmt Form des Spektrums. Grenzfrequenz fG = 1/τ. Je kürzer der Impuls, desto größer die benötigte Bandbreite.", keyTerms: ["Grenzfrequenz fG = 1/τ", "D = τ/T0", "Bestimmt Form des Spektrums", "Je kürzer der Impuls", "desto größer die benötigte Bandbreite"] },
      { cat: "Kap 4", q: "Wie lautet das Gesetz von Hartley?", a: "C = 2·B·log2(n) [bit/s]. Für ungestörten Kanal: B = Bandbreite, n = Amplitudenstufen. Binärkanal (n=2): C = 2B.", keyTerms: ["C = 2·B·log2 [bit/s]", "Für ungestörten Kanal", "Binärkanal", "B = Bandbreite", "n = Amplitudenstufen"] },
      { cat: "Kap 4", q: "Wie lautet das Shannon-Hartley-Gesetz?", a: "C = B · log2(1 + PS/PN) [bit/s]. Für gestörten Kanal: PS = Signalleistung, PN = Rauschleistung. Total gestört (PN >> PS): C = 0.", keyTerms: ["PS = Signalleistung", "PN = Rauschleistung", "Total gestört", "C = B · log2 [bit/s]", "Für gestörten Kanal"] },
      { cat: "Kap 4", q: "Wie rechnet man SNR in dB um?", a: "SNR [dB] = 10 · lg(PS/PN). Beispiel: 50 dB → PS/PN = 10^5 = 100.000. 30 dB → PS/PN = 1000.", keyTerms: ["PS/PN = 1000", "PS/PN = 10^5 = 100", "SNR [dB] = 10 · lg", "Beispiel"] },
      { cat: "Kap 4", q: "Welche Multiplexverfahren gibt es?", a: "SDM (Raum), FDM (Frequenz), TDM (Zeit), CDM (Code), WDM (Wellenlänge/optisch). Auch Kombinationen möglich, z.B. GSM nutzt SDM + FDM + TDM.", keyTerms: ["GSM nutzt SDM + FDM", "TDM", "CDM", "WDM", "Auch Kombinationen möglich"] },
      { cat: "Kap 4", q: "Was ist der Unterschied zwischen Basisband und Breitband?", a: "Basisband: Signal im Original-Frequenzbereich (z.B. Ethernet). Breitband: Signal wird durch Modulation in anderes Band verschoben (z.B. DSL/VDSL). Breitband = bessere Ausnutzung.", keyTerms: ["DSL/VDSL)", "Signal im Original-Frequenzbereich (z", "Breitband = bessere Ausnutzung", "Ethernet)", "Signal wird durch Modulation in"] },
      { cat: "Kap 5", q: "Was sind die drei Codierungsarten?", a: "1. Quellencodierung: Redundanz entfernen (Kompression). 2. Kanalcodierung: Redundanz hinzufügen (Fehlerschutz). 3. Leitungscodierung: Anpassung ans physische Medium.", keyTerms: ["Anpassung ans physische Medium", "Redundanz entfernen", "Redundanz hinzufügen", "Quellencodierung", "Kanalcodierung"] },
      { cat: "Kap 5", q: "Was ist die Hamming-Distanz?", a: "Der minimale Abstand (unterschiedliche Bitstellen) zwischen allen gültigen Codewörtern. Fehlererkennung: dmin ≥ e+1. Fehlerkorrektur: dmin ≥ 2t+1.", keyTerms: ["Der minimale Abstand zwischen allen", "dmin ≥ 2t+1", "Fehlererkennung", "dmin ≥ e+", "Fehlerkorrektur"] },
      { cat: "Kap 5", q: "Wie funktioniert der Hamming-Code (7,4)?", a: "4 Infostellen + 3 Prüfstellen (an Pos. 1,2,4). Gerade Parität in Prüfgruppen. Prüfzahl CBA als Dualzahl zeigt gestörte Stelle. dmin = 3 → Einfachfehler korrigierbar.", keyTerms: ["Prüfzahl CBA als Dualzahl zeigt", "4 Infostellen + 3 Prüfstellen", "Gerade Parität in Prüfgruppen", "dmin = 3", "Einfachfehler korrigierbar"] },
      { cat: "Kap 5", q: "Was ist CRC?", a: "Cyclic Redundancy Check: Nachricht wird mit Generatorpolynom G(x) geteilt. Rest wird angehängt. Empfänger prüft Teilbarkeit. Sehr leistungsfähig, z.B. CRC-32 bei Ethernet.", keyTerms: ["CRC-32 bei Ethernet", "Cyclic Redundancy Check", "Empfänger prüft Teilbarkeit", "Nachricht wird mit Generatorpolynom G geteilt", "Rest wird angehängt"] },
      { cat: "Kap 5", q: "Was ist der Manchestercode?", a: "Biphase-Leitungscode: Jedes Bit hat einen Pegelwechsel in der Mitte. Gleichspannungsfrei, gute Taktrückgewinnung. Nachteil: doppelte Bandbreite (Baudrate = 2 × Bitrate). Einsatz: 10 Mbit Ethernet.", keyTerms: ["doppelte Bandbreite", "10 Mbit Ethernet", "gute Taktrückgewinnung", "Biphase-Leitungscode", "Jedes Bit hat einen Pegelwechsel"] },
      { cat: "Kap 5", q: "Was ist der 4B/5B-Code?", a: "Blockcode: 4 Bit → 5 Bit. Max. eine führende 0, max. 2 abschließende 0 → keine langen Nullfolgen → Taktrückgewinnung. Einsatz: 100 Mbit Ethernet (+ NRZI).", keyTerms: ["100 Mbit Ethernet", "4 Bit", "5 Bit", "eine führende 0", "2 abschließende 0"] },
      { cat: "Kap 5", q: "Was ist ARQ vs. FEC?", a: "ARQ: Fehlererkennung + Wiederholung (Computernetze). FEC: Fehlerkorrektur ohne Wiederholung (Weltraum, CD/DVD). Hybridverfahren kombinieren beide.", keyTerms: ["CD/DVD)", "ARQ", "FEC", "Fehlerkorrektur ohne Wiederholung (Weltraum", "Fehlererkennung + Wiederholung"] },
      { cat: "Kap 5", q: "Was ist der Huffman-Code?", a: "Optimale Quellencodierung: Häufige Zeichen → kurze Codewörter, seltene → lange. Ist ein Präfix-Code. Minimiert mittlere Codewortlänge L nahe an Entropie H.", keyTerms: ["Minimiert mittlere Codewortlänge L nahe", "Optimale Quellencodierung", "Häufige Zeichen", "kurze Codewörter", "seltene"] }
